import { useState } from 'react';
import { useGameState, useGameActions } from '../../state/store.js';
import { GlossaryModal } from './GlossaryModal.js';
import { TECHNIQUE_NAMES } from './techniques.js';
import './hints.css';

export function HintBanner() {
  const { activeHint, hintLevel } = useGameState();
  const actions = useGameActions();
  const [showGlossary, setShowGlossary] = useState<string | null>(null);

  if (!activeHint) return null;

  const tname = TECHNIQUE_NAMES[activeHint.technique] ?? activeHint.technique;
  const isSpecialMessage = hintLevel === 0;

  return (
    <>
      <div className="hint-banner" role="status" aria-live="polite">
        <p className="hint-text">
          {activeHint.explanation}
          {hintLevel === 3 && (
            <>
              {' '}
              <button
                className="technique-link"
                onClick={() => setShowGlossary(activeHint.technique)}
              >
                {tname}
              </button>
            </>
          )}
        </p>
        {!isSpecialMessage && (
          <p className="hint-meta">
            Hint {hintLevel}/3 · tap hint again to {hintLevel === 3 ? 'try a new hint' : 'escalate'}
          </p>
        )}
        <button
          className="hint-dismiss"
          onClick={() => actions.dismissHint()}
          aria-label="Dismiss hint"
        >
          ×
        </button>
      </div>
      {showGlossary && (
        <GlossaryModal initial={showGlossary} onClose={() => setShowGlossary(null)} />
      )}
    </>
  );
}
