import { create } from 'zustand';
import { applyWin, type StreakState, type WinStats } from '../features/daily/streak.js';

const KEY = 'bilko_sudoku_streak_v1';
const empty: StreakState = { current: 0, longest: 0, freezes: 0, lastWinDate: null, completed: [] };

function load(): StreakState {
  try { return JSON.parse(localStorage.getItem(KEY) ?? '') ?? empty; } catch { return empty; }
}

interface StreakStore {
  state: StreakState;
  lastWinStats: WinStats | null;
  /** ISO date of the daily game currently active; null if not playing a daily. */
  currentDailyIso: string | null;
  recordWin: (date: string, stats: WinStats) => void;
  setCurrentDailyDate: (iso: string | null) => void;
  hydrate: (s: StreakState) => void;
}

export const useStreakStore = create<StreakStore>((set, get) => ({
  state: load(),
  lastWinStats: null,
  currentDailyIso: null,

  recordWin: (date, stats) => {
    const next = applyWin(get().state, date);
    set({ state: next, lastWinStats: stats });
    try { localStorage.setItem(KEY, JSON.stringify(next)); } catch {}
  },

  setCurrentDailyDate: (iso) => set({ currentDailyIso: iso }),

  hydrate: (s) => {
    set({ state: s });
    try { localStorage.setItem(KEY, JSON.stringify(s)); } catch {}
  },
}));
