import type { Board, Digit, Difficulty, GenerateOpts, Technique } from './index.js';
import { emptyBoard, setCell, clearCell } from './board.js';
import { solve, humanSolve, TECHNIQUE_RANK } from './solver.js';
import { isSolved } from './validate.js';

// Per-difficulty configuration.
// Difficulty is primarily determined by clue count; the maxRank cap ensures a
// puzzle doesn't require techniques far beyond the labelled level.
// We do NOT enforce a minimum required rank because landing in a narrow
// technique window is probabilistically rare and causes generator timeouts.
// Evil is the exception: it requires a puzzle that human techniques cannot fully
// solve (i.e., guessing is necessary).
interface DifficultySpec {
  /** Highest allowed TECHNIQUE_RANK (inclusive). */
  maxRank: number;
  /** Whether the puzzle must require guessing (evil only). */
  requiresGuess: boolean;
  clueMin: number;
  clueMax: number;
  /** Default generator timeout in ms. */
  timeoutMs: number;
}

const SPECS: Record<Difficulty, DifficultySpec> = {
  easy:   { maxRank: TECHNIQUE_RANK['hidden-single'],      requiresGuess: false, clueMin: 32, clueMax: 55, timeoutMs: 1000 },
  medium: { maxRank: TECHNIQUE_RANK['hidden-pair'],        requiresGuess: false, clueMin: 26, clueMax: 42, timeoutMs: 2000 },
  hard:   { maxRank: TECHNIQUE_RANK['box-line-reduction'], requiresGuess: false, clueMin: 22, clueMax: 37, timeoutMs: 3000 },
  expert: { maxRank: TECHNIQUE_RANK['x-wing'],             requiresGuess: false, clueMin: 18, clueMax: 34, timeoutMs: 5000 },
  master: { maxRank: TECHNIQUE_RANK['xy-wing'],            requiresGuess: false, clueMin: 17, clueMax: 32, timeoutMs: 8000 },
  evil:   { maxRank: TECHNIQUE_RANK['guess'],              requiresGuess: true,  clueMin: 17, clueMax: 30, timeoutMs: 10000 },
};

/** Shuffle an array in-place using Fisher-Yates. */
function shuffle<T>(arr: T[], rng: () => number): T[] {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    const tmp = arr[i]!;
    arr[i] = arr[j]!;
    arr[j] = tmp;
  }
  return arr;
}

/** Count filled cells. */
function clueCount(b: Board): number {
  let n = 0;
  for (let i = 0; i < 81; i++) if (b.cells[i] !== 0) n++;
  return n;
}

/**
 * Build a random fully-solved Sudoku board.
 * Strategy: fill row 0 randomly, then use the backtracking solver to complete.
 * Restart on dead-end (rare).
 */
function randomComplete(rng: () => number): Board {
  for (;;) {
    const digits = shuffle([1,2,3,4,5,6,7,8,9] as Digit[], rng);
    let b = emptyBoard();
    for (let c = 0; c < 9; c++) {
      b = setCell(b, c, digits[c]!);
    }
    const result = solve(b);
    if (result.ok) return result.board!;
    // Try again with a different first row (extremely rare to fail)
  }
}

/**
 * Check whether `puzzle` has the right difficulty.
 * Returns 'ok' | 'too_easy' | 'too_hard' | 'not_unique'
 */
function rateBoard(puzzle: Board, spec: DifficultySpec): 'ok' | 'too_easy' | 'too_hard' | 'not_unique' {
  const uniqueCheck = solve(puzzle, { earlyExitOnAmbiguity: true });
  if (!uniqueCheck.uniqueSolution) return 'not_unique';

  const cc = clueCount(puzzle);
  if (cc > spec.clueMax) return 'too_easy'; // not enough clues removed yet
  if (cc < spec.clueMin) return 'too_hard'; // too few clues

  const hr = humanSolve(puzzle);

  if (spec.requiresGuess) {
    // evil: must need guessing
    if (hr.solved) return 'too_easy';
    return 'ok';
  }

  if (!hr.solved) {
    // Non-evil: puzzle requires guessing → too hard
    return 'too_hard';
  }

  if (hr.highestRank > spec.maxRank) return 'too_hard';
  return 'ok';
}

export function generate(opts: GenerateOpts): { board: Board; solution: Board; difficulty: Difficulty } {
  const rng = opts.rng ?? Math.random;
  const sym = opts.symmetric ?? true;
  const spec = SPECS[opts.difficulty];
  const deadline = Date.now() + (opts.timeoutMs ?? spec.timeoutMs);

  let bestCandidate: Board | null = null;

  for (;;) {
    if (Date.now() > deadline) break;

    const solution = randomComplete(rng);
    let puzzle = solution;

    // Build symmetric removal order: pair (idx, 80-idx) together
    const indices = shuffle(Array.from({ length: 41 }, (_, i) => i), rng);

    for (const idx of indices) {
      if (Date.now() > deadline) break;

      const symIdx = 80 - idx;
      const prev = puzzle;

      // Remove the cell (and its symmetric counterpart if different)
      puzzle = clearCell(puzzle, idx);
      if (sym && symIdx !== idx) puzzle = clearCell(puzzle, symIdx);

      // Check if still uniquely solvable
      const check = solve(puzzle, { earlyExitOnAmbiguity: true });
      if (!check.uniqueSolution) {
        puzzle = prev; // restore
        continue;
      }

      // Check clue count bounds
      const cc = clueCount(puzzle);
      if (cc < spec.clueMin) {
        puzzle = prev;
        break; // can't remove any more without going below minimum
      }
    }

    // Rate the resulting puzzle
    const rating = rateBoard(puzzle, spec);
    if (rating === 'ok') {
      return { board: puzzle, solution, difficulty: opts.difficulty };
    }

    // Keep as best candidate if it's close (unique solution, at least)
    const uniqueCheck = solve(puzzle, { earlyExitOnAmbiguity: true });
    if (uniqueCheck.uniqueSolution) {
      bestCandidate = puzzle;
    }

    // If we've used too much time, fall back to best candidate
    if (Date.now() > deadline) break;
  }

  // Graceful timeout: return best candidate or a freshly-solved puzzle
  if (bestCandidate) {
    const sol = solve(bestCandidate);
    return { board: bestCandidate, solution: sol.board!, difficulty: opts.difficulty };
  }

  // Last resort: return a complete puzzle (0 clues removed)
  const solution = randomComplete(rng);
  return { board: solution, solution, difficulty: opts.difficulty };
}
