import { NumberPad } from '../components/pad/index.js';
import { useGameState } from '../state/store.js';

export function PadSlot() {
  const { board, selection, noteMode, primedDigit } = useGameState();
  return (
    <NumberPad
      board={board}
      selection={selection}
      noteMode={noteMode}
      primedDigit={primedDigit}
    />
  );
}
