import { create } from 'zustand';
import {
  type Board,
  type Difficulty,
  type Hint,
  emptyBoard,
  fromString,
  toString as boardToString,
  generate,
  validate,
  isSolved,
  deterministicRng,
  nextHint,
  setCell,
  clearCell,
  setCandidate,
} from '../engine/index.js';
import { bus } from '../lib/bus.js';

interface UndoEntry {
  board: Board;
  selection: { row: number; col: number } | null;
  noteMode: boolean;
  candidatesSnapshot: Uint16Array;
}

export interface GameState {
  board: Board;
  solution: Board;
  difficulty: Difficulty;
  startedAt: number;
  timeMs: number;
  paused: boolean;
  solved: boolean;
  mistakes: number;
  hintsUsed: number;

  selection: { row: number; col: number } | null;
  noteMode: boolean;
  primedDigit: number | null;
  conflicts: number[];

  hintLevel: 0 | 1 | 2 | 3;
  activeHint: Hint | null;
  hintHighlight: number[];

  /** ISO date ('YYYY-MM-DD') when this is today's daily game; null for free-play or replays. */
  dailyDate: string | null;

  undoStack: UndoEntry[];
  redoStack: UndoEntry[];
}

export interface Actions {
  newGame: (difficulty: Difficulty, seed?: number, dailyDate?: string) => void;
  placeAt: (row: number, col: number, value: number | null, isNote: boolean) => void;
  selectCell: (row: number, col: number) => void;
  setNoteMode: (on: boolean) => void;
  undo: () => void;
  redo: () => void;
  pause: (on: boolean) => void;
  resume: () => void;
  loadFromCloud: (blob: SerializedSave) => void;
  escalateHint: () => void;
  dismissHint: () => void;
}

export const STORAGE_KEY = 'bilko_sudoku_save_v1';
const MAX_STACK = 200;

export interface SerializedSave {
  v: 1;
  board: string;
  solution: string;
  givens: number[];
  difficulty: Difficulty;
  startedAt: number;
  timeMs: number;
  mistakes: number;
  hintsUsed: number;
}

function snapshot(s: GameState): UndoEntry {
  return {
    board: s.board,
    selection: s.selection,
    noteMode: s.noteMode,
    candidatesSnapshot: new Uint16Array(s.board.candidates),
  };
}

export const DAILY_STORAGE_KEY = (date: string) => `bilko_sudoku_daily_${date}`;

function persist(s: GameState) {
  const blob: SerializedSave = {
    v: 1,
    board: boardToString(s.board),
    solution: boardToString(s.solution),
    givens: Array.from(s.board.givens),
    difficulty: s.difficulty,
    startedAt: s.startedAt,
    timeMs: s.timeMs,
    mistakes: s.mistakes,
    hintsUsed: s.hintsUsed,
  };
  const key = s.dailyDate ? DAILY_STORAGE_KEY(s.dailyDate) : STORAGE_KEY;
  try { localStorage.setItem(key, JSON.stringify(blob)); } catch {}
}

let persistTimer: ReturnType<typeof setTimeout> | null = null;

export function debouncePersist(s: GameState) {
  if (persistTimer) clearTimeout(persistTimer);
  persistTimer = setTimeout(() => persist(s), 400);
}

export const useStore = create<GameState & { actions: Actions }>((set, get) => ({
  board: emptyBoard(),
  solution: emptyBoard(),
  difficulty: 'easy',
  startedAt: Date.now(),
  timeMs: 0,
  paused: false,
  solved: false,
  mistakes: 0,
  hintsUsed: 0,
  selection: null,
  noteMode: false,
  primedDigit: null,
  conflicts: [],
  hintLevel: 0,
  activeHint: null,
  hintHighlight: [],
  dailyDate: null,
  undoStack: [],
  redoStack: [],

  actions: {
    newGame: (difficulty, seed, dailyDate) => {
      const rng = seed != null ? deterministicRng(seed) : undefined;
      const { board: rawBoard, solution } = generate({ difficulty, rng });
      // generate() doesn't stamp givens; mark every non-zero cell as given
      const givensMask = new Uint8Array(rawBoard.cells.map(c => (c !== 0 ? 1 : 0)));
      const board: Board = { ...rawBoard, givens: givensMask };
      set({
        board, solution, difficulty,
        startedAt: Date.now(), timeMs: 0, paused: false, solved: false,
        mistakes: 0, hintsUsed: 0, selection: null, noteMode: false,
        primedDigit: null, conflicts: [],
        hintLevel: 0, activeHint: null, hintHighlight: [],
        dailyDate: dailyDate ?? null,
        undoStack: [], redoStack: [],
      });
      if (dailyDate) {
        // Clear this day's in-progress save; free-play save is preserved
        try { localStorage.removeItem(DAILY_STORAGE_KEY(dailyDate)); } catch {}
      } else {
        try { localStorage.removeItem(STORAGE_KEY); } catch {}
      }
    },

    placeAt: (row, col, value, isNote) => {
      const s = get();
      if (s.solved || s.paused) return;
      let r = row; let c = col;
      if (r < 0) {
        if (!s.selection) return;
        r = s.selection.row; c = s.selection.col;
      }
      const idx = r * 9 + c;
      if (s.board.givens[idx]) return;
      const before = snapshot(s);
      let nextBoard = s.board;
      if (isNote && value != null) {
        const cur = (s.board.candidates[idx]! >> value) & 1;
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        nextBoard = setCandidate(s.board, idx, value as any, cur === 0);
      } else if (value == null) {
        nextBoard = clearCell(s.board, idx);
      } else {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        nextBoard = setCell(s.board, idx, value as any);
      }
      const conflicts = validate(nextBoard).conflicts;
      const isMistake = !isNote && value != null && s.solution.cells[idx] !== value;
      const solved = isSolved(nextBoard) && conflicts.length === 0;
      const next: Partial<GameState> = {
        board: nextBoard,
        conflicts,
        mistakes: s.mistakes + (isMistake ? 1 : 0),
        undoStack: [...s.undoStack.slice(-(MAX_STACK - 1)), before],
        redoStack: [],
        solved,
      };
      set(next);
      debouncePersist({ ...s, ...next } as GameState);
      if (solved) {
        bus.emit('puzzleSolved', {
          difficulty: s.difficulty,
          timeMs: s.timeMs,
          mistakes: s.mistakes,
          hintsUsed: s.hintsUsed,
        });
        const clearKey = s.dailyDate ? DAILY_STORAGE_KEY(s.dailyDate) : STORAGE_KEY;
        try { localStorage.removeItem(clearKey); } catch {}
      }
    },

    selectCell: (row, col) => set({ selection: row < 0 ? null : { row, col } }),

    setNoteMode: on => set({ noteMode: on }),

    undo: () => {
      const s = get();
      if (s.undoStack.length === 0) return;
      const top = s.undoStack[s.undoStack.length - 1]!;
      set({
        board: top.board,
        selection: top.selection,
        noteMode: top.noteMode,
        undoStack: s.undoStack.slice(0, -1),
        redoStack: [...s.redoStack, snapshot(s)],
        conflicts: validate(top.board).conflicts,
      });
      debouncePersist(get());
    },

    redo: () => {
      const s = get();
      if (s.redoStack.length === 0) return;
      const top = s.redoStack[s.redoStack.length - 1]!;
      set({
        board: top.board,
        selection: top.selection,
        noteMode: top.noteMode,
        redoStack: s.redoStack.slice(0, -1),
        undoStack: [...s.undoStack, snapshot(s)],
        conflicts: validate(top.board).conflicts,
      });
      debouncePersist(get());
    },

    pause: on => set({ paused: on }),

    resume: () => {
      try {
        // Prefer today's in-progress daily over free-play save
        const todayIso = new Date().toISOString().slice(0, 10);
        const dailyKey = DAILY_STORAGE_KEY(todayIso);
        let raw = localStorage.getItem(dailyKey);
        const resumedDailyDate = raw ? todayIso : null;
        if (!raw) raw = localStorage.getItem(STORAGE_KEY);
        if (!raw) return;
        const blob = JSON.parse(raw) as SerializedSave;
        if (blob.v !== 1) return;
        const board = fromString(blob.board);
        const solution = fromString(blob.solution);
        const givens = new Uint8Array(blob.givens);
        const restored: Board = { ...board, givens };
        set({
          board: restored, solution, difficulty: blob.difficulty,
          startedAt: blob.startedAt, timeMs: blob.timeMs,
          mistakes: blob.mistakes, hintsUsed: blob.hintsUsed,
          paused: false, solved: false,
          selection: null, noteMode: false, primedDigit: null,
          conflicts: validate(restored).conflicts,
          dailyDate: resumedDailyDate,
          undoStack: [], redoStack: [],
        });
      } catch {}
    },

    escalateHint: () => {
      const s = get();
      if (s.solved || s.paused) return;
      if (s.conflicts.length > 0) {
        set({
          activeHint: { technique: 'naked-single', cells: [], explanation: 'Fix conflicts first.', level: 1 },
          hintHighlight: s.conflicts,
          hintLevel: 0,
        });
        return;
      }
      const nextLevel = (s.hintLevel === 3 ? 1 : s.hintLevel + 1) as 1 | 2 | 3;
      const hint = nextHint(s.board, nextLevel);
      if (!hint) {
        set({
          activeHint: { technique: 'naked-single', cells: [], explanation: 'No more hints available — the puzzle is fully constrained.', level: 1 },
          hintLevel: 0,
          hintHighlight: [],
        });
        return;
      }
      set({ activeHint: hint, hintLevel: nextLevel, hintHighlight: hint.cells });
      if (nextLevel === 3) {
        set({ hintsUsed: s.hintsUsed + 1 });
        if (hint.cells.length === 1 && hint.digit) {
          const idx = hint.cells[0]!;
          const row = Math.floor(idx / 9);
          const col = idx % 9;
          get().actions.placeAt(row, col, hint.digit, false);
          setTimeout(() => get().actions.dismissHint(), 2000);
        }
      }
    },

    dismissHint: () => set({ activeHint: null, hintLevel: 0, hintHighlight: [] }),

    loadFromCloud: (blob) => {
      const board = fromString(blob.board);
      const solution = fromString(blob.solution);
      const givens = new Uint8Array(blob.givens);
      const restored: Board = { ...board, givens };
      set({
        board: restored, solution, difficulty: blob.difficulty,
        startedAt: blob.startedAt, timeMs: blob.timeMs,
        mistakes: blob.mistakes, hintsUsed: blob.hintsUsed,
        paused: false, solved: false,
        selection: null, noteMode: false, primedDigit: null,
        conflicts: validate(restored).conflicts,
        undoStack: [], redoStack: [],
      });
      debouncePersist(get());
    },
  },
}));

// Individual selectors avoid the useShallow CJS/ESM conflict while preventing
// infinite loops — each selector returns a stable primitive or reference.
export function useGameState() {
  const board          = useStore(s => s.board);
  const solution       = useStore(s => s.solution);
  const difficulty     = useStore(s => s.difficulty);
  const timeMs         = useStore(s => s.timeMs);
  const paused         = useStore(s => s.paused);
  const solved         = useStore(s => s.solved);
  const mistakes       = useStore(s => s.mistakes);
  const hintsUsed      = useStore(s => s.hintsUsed);
  const selection      = useStore(s => s.selection);
  const noteMode       = useStore(s => s.noteMode);
  const primedDigit    = useStore(s => s.primedDigit);
  const conflicts      = useStore(s => s.conflicts);
  const hintLevel      = useStore(s => s.hintLevel);
  const activeHint     = useStore(s => s.activeHint);
  const hintHighlight  = useStore(s => s.hintHighlight);
  const canUndo        = useStore(s => s.undoStack.length > 0);
  const canRedo        = useStore(s => s.redoStack.length > 0);
  return { board, solution, difficulty, timeMs, paused, solved, mistakes, hintsUsed, selection, noteMode, primedDigit, conflicts, hintLevel, activeHint, hintHighlight, canUndo, canRedo };
}

export const useGameActions = () => useStore(s => s.actions);

if (typeof window !== 'undefined') {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  (window as any).__sudoku_store = useStore;
}

