import { useState, useEffect, useRef } from 'react';
import { fromString, setCell, setCandidate, clearCell, validate } from '../engine/index.js';
import type { Board, Digit } from '../engine/index.js';
import { bus } from '../lib/bus.js';
import { useStore } from '../state/store.js';
import { unitsCompletedAfterPlacement } from '../features/anim/unit-complete.js';
import { Grid } from '../components/grid/index.js';

// Well-known easy puzzle — gives us real given cells for dev/testing.
// Row 0: 5,3,_,_,7,_,_,_,_  Row 4: 4,_,_,8,_,3,_,_,1  etc.
const DEV_PUZZLE = '530070000600195000098000060800060003400803001700020006060000280000419005000080079';

export function GridSlot() {
  const [board, setBoard] = useState<Board>(() => fromString(DEV_PUZZLE));
  // boardRef mirrors board state synchronously so event handlers see current values
  // without stale closures or side effects inside setState updaters.
  const boardRef = useRef(fromString(DEV_PUZZLE));
  const [selection, setSelection] = useState<{ row: number; col: number } | null>(null);
  const [conflicts, setConflicts] = useState<number[]>([]);
  const hintHighlight = useStore(s => s.hintHighlight);

  useEffect(() => {
    const unsub1 = bus.on('cellSelected', ({ row, col }) => {
      setSelection(row < 0 ? null : { row, col });
    });

    const unsub2 = bus.on('cellChanged', ({ row, col, value, isNote }) => {
      const prev = boardRef.current;
      const idx = row * 9 + col;
      if (prev.givens[idx] === 1) return;

      let next: Board;
      if (isNote && value !== null) {
        const currentOn = ((prev.candidates[idx] ?? 0) & (1 << value)) !== 0;
        next = setCandidate(prev, idx, value as Digit, !currentOn);
      } else if (value !== null) {
        next = setCell(prev, idx, value as Digit);
      } else {
        next = clearCell(prev, idx);
      }

      const { conflicts: c } = validate(next);
      boardRef.current = next;
      setBoard(next);
      setConflicts(c);

      if (!isNote && value !== null) {
        if (prev.cells[idx] === 0) {
          const events = unitsCompletedAfterPlacement(prev, next, idx);
          events.forEach(e => bus.emit('unitCompleted', e));
        }
        if (c.includes(idx)) {
          bus.emit('mistakePlaced', { idx, conflicts: c });
        }
      }
    });

    return () => {
      unsub1();
      unsub2();
    };
  }, []);

  return <Grid board={board} selection={selection} conflicts={conflicts} hintHighlight={hintHighlight} />;
}
