import { useEffect, useState, type ReactNode } from 'react';
import { useGameState } from '../../state/store.js';
import { Tutorial, hasSeenTutorial } from '../tutorial/index.js';
import './layout.css';

/**
 * Full-bleed layout for the Sudoku app.
 *
 * Responsibilities:
 *   - Manage tutorial visibility (auto-open on first visit, ?-help reopens it).
 *   - Render thin top + bottom chrome bars wrapped around the play-area slot.
 *   - Compose children (engine + grid) inside the play-area so the existing
 *     slot structure keeps working unchanged.
 *
 * Children expected (in order):
 *   - [0] new-game / hint banner / engine inner
 *   - [1] grid
 *
 * The number pad + toolbar render below as `bottomBar` props so they can live
 * inside `<div class="bottom-bar">` for full-bleed alignment.
 */

interface Props {
  playArea: ReactNode;   // engine wrapper + grid + hint banner (and daily hero on top)
  bottomBar: ReactNode;  // number pad + toolbar
  topBarLeft?: ReactNode;
  topBarRight?: ReactNode;
}

export function GameLayout({ playArea, bottomBar, topBarLeft, topBarRight }: Props) {
  // Tutorial open state — initialise from localStorage on mount so SSR-style
  // hydration mismatch never flashes the dialog before the gate runs.
  const [tutorialOpen, setTutorialOpen] = useState(false);
  useEffect(() => {
    if (!hasSeenTutorial()) setTutorialOpen(true);
  }, []);

  const { difficulty, timeMs } = useGameState();
  const timer = formatTime(timeMs);

  return (
    <div className="game-layout">
      <div className="top-bar" role="region" aria-label="Game status">
        <div className="top-bar-left">
          <span className="diff-chip" aria-label={`Difficulty ${difficulty}`}>{difficulty}</span>
          <span className="timer" aria-label={`Elapsed time ${timer}`}>{timer}</span>
          {topBarLeft}
        </div>
        <div className="top-bar-right">
          <button
            type="button"
            className="help-btn"
            aria-label="How to play"
            title="How to play"
            onClick={() => setTutorialOpen(true)}
          >
            ?
          </button>
          {topBarRight}
        </div>
      </div>

      <div className="play-area">
        {playArea}
      </div>

      <div className="bottom-bar">
        {bottomBar}
      </div>

      <Tutorial open={tutorialOpen} onClose={() => setTutorialOpen(false)} />
    </div>
  );
}

/** O(1) — millis to MM:SS clock. */
function formatTime(ms: number): string {
  const total = Math.max(0, Math.floor(ms / 1000));
  const m = Math.floor(total / 60);
  const s = total % 60;
  return `${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
}
