import { useEffect } from 'react';
import { create } from 'zustand';
import { useUnlocks } from 'host-kit';
import { bus } from '../../lib/bus.js';

// ── Toast store ───────────────────────────────────────────────────────────────

interface Toast { id: number; message: string }

let _toastId = 0;

export const useToastStore = create<{ toasts: Toast[]; show(msg: string): void }>((set) => ({
  toasts: [],
  show(message) {
    const id = ++_toastId;
    set((s) => ({ toasts: [...s.toasts, { id, message }] }));
    setTimeout(() => set((s) => ({ toasts: s.toasts.filter((t) => t.id !== id) })), 4000);
  },
}));

// ── Achievement subscriber ────────────────────────────────────────────────────

export function usePuzzleSolvedSubscriber() {
  const { unlocks, unlock, lastCrossUnlock } = useUnlocks('sudoku');
  const show = useToastStore((s) => s.show);

  const hasUnlock = (key: string) => unlocks.some((u) => u.key === key);

  useEffect(() => {
    if (lastCrossUnlock) {
      show(`🎉 ${lastCrossUnlock.name} unlocked — you've solved a Sudoku AND a MindSwiffer.`);
    }
  }, [lastCrossUnlock, show]);

  useEffect(() => {
    return bus.on('puzzleSolved', () => {
      if (hasUnlock('first_win')) return;
      void (async () => {
        const ok = await unlock('first_win');
        if (ok) show('🏆 Achievement unlocked: First win');
      })();
    });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [unlocks, unlock, show]);
}
