import { useEffect, useState, type ReactNode } from 'react';
import { useStore, useGameState, useGameActions } from '../state/store.js';
import { bus } from '../lib/bus.js';
import { Confetti } from '../features/anim/Confetti.js';
import { CloudSaveBridge } from '../state/cloud-save.js';

export function EngineSlot({ children }: { children: ReactNode }) {
  // 1-second timer tick, pauses when game is paused or solved
  useEffect(() => {
    const id = setInterval(() => {
      const s = useStore.getState();
      if (s.paused || s.solved) return;
      useStore.setState({ timeMs: s.timeMs + 1000 });
    }, 1000);
    return () => clearInterval(id);
  }, []);

  // Pause on tab visibility change
  useEffect(() => {
    function onVisibility() {
      useStore.getState().actions.pause(document.visibilityState === 'hidden');
    }
    document.addEventListener('visibilitychange', onVisibility);
    return () => document.removeEventListener('visibilitychange', onVisibility);
  }, []);

  const [winning, setWinning] = useState(false);
  useEffect(() => {
    return bus.on('puzzleSolved', () => setWinning(true));
  }, []);

  const s = useGameState();
  const actions = useGameActions();
  const isEmpty = s.board.cells.every(c => c === 0);

  return (
    <>
      {winning && <Confetti onDone={() => setWinning(false)} />}
      <div data-slot="engine" className="flex flex-col gap-4">
        <CloudSaveBridge />
        {!s.solved && isEmpty && (
          <div className="new-game-bar flex gap-2 justify-center py-2">
            <button onClick={() => actions.newGame('easy')}>New Easy</button>
            <button onClick={() => actions.newGame('medium')}>New Medium</button>
            <button onClick={() => actions.newGame('hard')}>New Hard</button>
            <button onClick={() => actions.newGame('expert')}>New Expert</button>
          </div>
        )}
        {children}
      </div>
    </>
  );
}
