import { useEffect, useState } from 'react';
import './tutorial.css';

/**
 * First-run "How to play" walkthrough. Three short, Sudoku-specific steps.
 *
 *   1) The rule        — fill 1-9 once per row, column, and 3×3 box
 *   2) Pencil marks    — long-press a digit (or tap ✏️) to drop candidates
 *   3) Difficulty +    — pick a level, play the daily, escalate hints 3 times
 *      hints + daily
 *
 * Persistence:
 *   - `sudoku_seen_tutorial` in localStorage gates auto-open on first visit.
 *   - The ?-help icon in the top bar reopens it anytime.
 *
 * The component is fully self-contained — no store dependencies — so it can
 * also be mounted in isolation for E2E testing.
 */

export const TUTORIAL_STORAGE_KEY = 'sudoku_seen_tutorial';

interface Props {
  open: boolean;
  onClose: () => void;
}

const STEP_COUNT = 3;

export function Tutorial({ open, onClose }: Props) {
  const [step, setStep] = useState(0);

  // Reset to step 0 every time the tutorial reopens
  useEffect(() => { if (open) setStep(0); }, [open]);

  // Escape closes; arrows navigate
  useEffect(() => {
    if (!open) return;
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        e.preventDefault();
        finish();
      } else if (e.key === 'ArrowRight') {
        e.preventDefault();
        setStep(s => Math.min(STEP_COUNT - 1, s + 1));
      } else if (e.key === 'ArrowLeft') {
        e.preventDefault();
        setStep(s => Math.max(0, s - 1));
      } else if (e.key === 'Enter') {
        e.preventDefault();
        if (step >= STEP_COUNT - 1) finish();
        else setStep(s => s + 1);
      }
    }
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [open, step]);

  function finish() {
    try { localStorage.setItem(TUTORIAL_STORAGE_KEY, '1'); } catch {}
    onClose();
  }

  if (!open) return null;

  return (
    <div
      className="tut-backdrop"
      role="dialog"
      aria-modal="true"
      aria-label="How to play Sudoku"
      onClick={finish}
    >
      <div className="tut-sheet" onClick={e => e.stopPropagation()}>
        <p className="tut-step-count">Step {step + 1} of {STEP_COUNT}</p>

        {step === 0 && <StepRule />}
        {step === 1 && <StepNotes />}
        {step === 2 && <StepLevelsHints />}

        <div className="tut-footer">
          <div className="tut-dots" role="tablist" aria-label="Tutorial steps">
            {Array.from({ length: STEP_COUNT }, (_, i) => (
              <button
                key={i}
                className={`tut-dot${i === step ? ' active' : ''}`}
                onClick={() => setStep(i)}
                role="tab"
                aria-selected={i === step}
                aria-label={`Go to step ${i + 1}`}
              />
            ))}
          </div>
          <div className="tut-actions">
            {step > 0 && (
              <button className="tut-btn ghost" onClick={() => setStep(s => s - 1)}>
                Back
              </button>
            )}
            {step < STEP_COUNT - 1 ? (
              <>
                <button className="tut-btn skip" onClick={finish}>Skip</button>
                <button className="tut-btn primary" onClick={() => setStep(s => s + 1)}>
                  Next
                </button>
              </>
            ) : (
              <button className="tut-btn primary" onClick={finish}>Got it</button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ───────────────────────────── Step contents ────────────────────────────── */

function StepRule() {
  // Highlight row 4, column 4, and the center 3×3 box around (4,4)
  // to teach the three constraint types in one mini-grid.
  function cellClass(r: number, c: number): string {
    const cls: string[] = [];
    const inRow = r === 4;
    const inCol = c === 4;
    const inBox = Math.floor(r / 3) === 1 && Math.floor(c / 3) === 1;
    if (r === 4 && c === 4) cls.push('hero', 'entered');
    else {
      if (inRow) cls.push('row-hl');
      if (inCol) cls.push('col-hl');
      if (inBox) cls.push('box-hl');
    }
    return cls.join(' ');
  }

  // Pre-fill the highlighted peers with the sample digits 1..8 in some
  // valid-looking order so newcomers see the "each digit once" idea.
  const ROW_DIGITS  = [3, 8, 1, 6, 0, 9, 5, 2, 7]; // (0 = the hero cell)
  const COL_DIGITS  = [2, 5, 9, 7, 0, 4, 1, 8, 6];
  // We render the hero as "4" so the puzzle visually agrees with the explanation.
  const HERO = 4;

  return (
    <>
      <h2 className="tut-title">Every row, column, and box has 1-9</h2>
      <p className="tut-copy">
        Fill the empty cells so each <strong>row</strong>, each <strong>column</strong>,
        and each <strong>3×3 box</strong> contains every digit from 1 to 9 exactly once.
      </p>
      <div className="tut-demo" aria-hidden="true">
        {Array.from({ length: 9 }, (_, r) =>
          Array.from({ length: 9 }, (_, c) => {
            const isHero = r === 4 && c === 4;
            let label = '';
            if (isHero) label = String(HERO);
            else if (r === 4 && ROW_DIGITS[c]) label = String(ROW_DIGITS[c]);
            else if (c === 4 && COL_DIGITS[r]) label = String(COL_DIGITS[r]);

            return (
              <div
                key={`${r}-${c}`}
                className={`tcell ${cellClass(r, c)}`}
                data-tut-row={r}
                data-tut-col={c}
              >
                {label}
              </div>
            );
          })
        )}
      </div>
    </>
  );
}

function StepNotes() {
  // Show two cells side-by-side: one with pencil marks, one with a placed digit.
  // We render a compact 3-col mini-grid (3 cells wide, 3 tall) to keep focus.
  // Cell layout:
  //   [ notes 2,4,7 ] [ placed 5 ] [ notes 1,3 ]
  //   [   given 8   ] [ given 9 ] [   notes 6  ]
  //   [    empty    ] [ placed 3 ] [   given 2  ]
  const notes = (set: number[]) => (
    <div className="tnotes">
      {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(d => (
        <span key={d} style={{ visibility: set.includes(d) ? 'visible' : 'hidden' }}>{d}</span>
      ))}
    </div>
  );

  return (
    <>
      <h2 className="tut-title">Tap and hold a digit to drop notes</h2>
      <p className="tut-copy">
        Not sure what fits a cell yet? Select the cell, then{' '}
        <strong>long-press a digit</strong> on the number pad — or tap the{' '}
        <strong>✏️ pencil</strong> in the toolbar — to leave small candidate marks.
        Notes are the difference between guessing and solving.
      </p>
      <div
        className="tut-demo"
        aria-hidden="true"
        style={{ gridTemplateColumns: 'repeat(3, 1fr)', maxWidth: 180 }}
      >
        <div className="tcell" data-tut-row="0" data-tut-col="0">{notes([2, 4, 7])}</div>
        <div className="tcell entered" data-tut-row="0" data-tut-col="1">5</div>
        <div className="tcell" data-tut-row="0" data-tut-col="2">{notes([1, 3])}</div>
        <div className="tcell" data-tut-row="1" data-tut-col="0">8</div>
        <div className="tcell" data-tut-row="1" data-tut-col="1">9</div>
        <div className="tcell" data-tut-row="1" data-tut-col="2">{notes([6])}</div>
        <div className="tcell" data-tut-row="2" data-tut-col="0"></div>
        <div className="tcell entered" data-tut-row="2" data-tut-col="1">3</div>
        <div className="tcell" data-tut-row="2" data-tut-col="2">2</div>
      </div>
      <p className="tut-copy" style={{ fontSize: 13, opacity: 0.7 }}>
        Tip: notes auto-clear when you place a final digit.
      </p>
    </>
  );
}

function StepLevelsHints() {
  return (
    <>
      <h2 className="tut-title">Six levels. A new daily. Smart hints.</h2>
      <p className="tut-copy">
        Free-play comes in six difficulties, each generated fresh:
      </p>
      <div className="tut-diffs" aria-hidden="true">
        <span className="tut-diff featured">Easy</span>
        <span className="tut-diff">Medium</span>
        <span className="tut-diff">Hard</span>
        <span className="tut-diff">Expert</span>
        <span className="tut-diff">Master</span>
        <span className="tut-diff">Evil</span>
      </div>

      <div className="tut-feature-row">
        <span className="tut-feature-icon" aria-hidden="true">📅</span>
        <p className="tut-feature-text">
          <strong>Daily puzzle:</strong> one new puzzle every day, shared with everyone.
          Win days build a streak; miss a day and a freeze can save it.
        </p>
      </div>

      <div className="tut-feature-row">
        <span className="tut-feature-icon" aria-hidden="true">💡</span>
        <p className="tut-feature-text">
          <strong>3-tier hints:</strong> tap once for a region, again to narrow it,
          a third time to solve the step and learn the technique name.
        </p>
      </div>

      <div className="tut-feature-row">
        <span className="tut-feature-icon" aria-hidden="true">↶</span>
        <p className="tut-feature-text">
          <strong>Unlimited undo:</strong> no penalty for experimenting.
          Your game auto-saves and resumes when you come back.
        </p>
      </div>
    </>
  );
}

/**
 * Helper: returns true if the user has already dismissed the tutorial at least once.
 * Safe to call before any state hooks (used by GameLayout to decide initial open state).
 */
export function hasSeenTutorial(): boolean {
  try { return localStorage.getItem(TUTORIAL_STORAGE_KEY) === '1'; }
  catch { return false; }
}
