import { useEffect } from 'react';
import type { Board } from '../../engine/index.js';
import { bus } from '../../lib/bus.js';
import { unitCellIndices } from '../../features/anim/unit-complete.js';
import { Cell } from './Cell.js';
import './grid.css';

interface Props {
  board: Board;
  selection: { row: number; col: number } | null;
  conflicts: number[];
  hintHighlight?: number[];
}

export function Grid({ board, selection, conflicts, hintHighlight = [] }: Props) {
  useEffect(() => {
    const unsubUnit = bus.on('unitCompleted', ({ kind, index }) => {
      const cells = unitCellIndices(kind, index);
      cells.forEach(i => {
        document.querySelector(`[data-cell-idx="${i}"]`)?.setAttribute('data-unit-complete', kind);
      });
      setTimeout(() => {
        cells.forEach(i => {
          document.querySelector(`[data-cell-idx="${i}"]`)?.removeAttribute('data-unit-complete');
        });
      }, 400);
    });

    const unsubMistake = bus.on('mistakePlaced', ({ conflicts: conflictCells }) => {
      new Set(conflictCells).forEach(i => {
        const el = document.querySelector(`[data-cell-idx="${i}"]`);
        if (!el) return;
        el.classList.add('mistake-shake');
        setTimeout(() => el.classList.remove('mistake-shake'), 150);
      });
    });

    return () => { unsubUnit(); unsubMistake(); };
  }, []);

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (!selection || selection.row < 0) return;
      const { row, col } = selection;

      if (e.key.startsWith('Arrow')) {
        e.preventDefault();
        const dr = e.key === 'ArrowUp' ? -1 : e.key === 'ArrowDown' ? 1 : 0;
        const dc = e.key === 'ArrowLeft' ? -1 : e.key === 'ArrowRight' ? 1 : 0;
        bus.emit('cellSelected', { row: (row + dr + 9) % 9, col: (col + dc + 9) % 9 });
        return;
      }

      if (/^[1-9]$/.test(e.key)) {
        e.preventDefault();
        bus.emit('cellChanged', { row, col, value: Number(e.key), isNote: e.shiftKey });
        return;
      }

      if (e.key === 'Backspace' || e.key === 'Delete' || e.key === '0') {
        e.preventDefault();
        bus.emit('cellChanged', { row, col, value: null, isNote: false });
        return;
      }

      if (e.key === 'Escape') {
        bus.emit('cellSelected', { row: -1, col: -1 });
      }
    }

    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [selection]);

  const selectedIdx =
    selection && selection.row >= 0 ? selection.row * 9 + selection.col : -1;
  const selectedDigit = selectedIdx >= 0 ? (board.cells[selectedIdx] ?? 0) : 0;

  return (
    <div className="sudoku-grid" role="grid" aria-label="Sudoku puzzle">
      {Array.from({ length: 9 }, (_, rowIdx) => (
        // role="row" with display:contents is invisible to CSS grid but satisfies ARIA hierarchy
        <div key={rowIdx} role="row" style={{ display: 'contents' }}>
          {Array.from({ length: 9 }, (_, colIdx) => {
            const i = rowIdx * 9 + colIdx;
            const isSelected = selectedIdx === i;
            const isPeer =
              !isSelected &&
              selection !== null &&
              selection.row >= 0 &&
              (selection.row === rowIdx ||
                selection.col === colIdx ||
                (Math.floor(selection.row / 3) === Math.floor(rowIdx / 3) &&
                  Math.floor(selection.col / 3) === Math.floor(colIdx / 3)));
            const isSameDigit = !isSelected && selectedDigit > 0 && (board.cells[i] ?? 0) === selectedDigit;

            return (
              <Cell
                key={i}
                idx={i}
                row={rowIdx}
                col={colIdx}
                board={board}
                isSelected={isSelected}
                isPeer={isPeer}
                isSameDigit={isSameDigit}
                isConflict={conflicts.includes(i)}
                isHintHighlight={hintHighlight.includes(i)}
                onClick={() => bus.emit('cellSelected', { row: rowIdx, col: colIdx })}
              />
            );
          })}
        </div>
      ))}
    </div>
  );
}
