import { Toolbar } from '../components/pad/index.js';
import { useGameState } from '../state/store.js';

export function ToolbarSlot() {
  const { canUndo, canRedo, noteMode, hintsUsed } = useGameState();
  return (
    <Toolbar
      canUndo={canUndo}
      canRedo={canRedo}
      noteMode={noteMode}
      hintsUsed={hintsUsed}
    />
  );
}
