import type { Board, Hint, Digit, CellIdx } from './index.js';
import { isSolved } from './validate.js';
import { HUMAN_TECHNIQUES, TechResult } from './techniques.js';
import { ROW_OF, COL_OF, BOX_OF, ROW_UNITS, COL_UNITS, BOX_UNITS } from './peers.js';

function regionFor(cell: CellIdx, tech: TechResult): CellIdx[] {
  // Return the full unit (row/col/box) that the technique's focus cells belong to.
  const focus = tech.focusCells;
  if (focus.length === 0) return [];

  // Check if all focus cells share a row
  const row = ROW_OF[focus[0]!]!;
  if (focus.every(i => ROW_OF[i] === row)) return [...ROW_UNITS[row]!];

  // Check if all focus cells share a col
  const col = COL_OF[focus[0]!]!;
  if (focus.every(i => COL_OF[i] === col)) return [...COL_UNITS[col]!];

  // Check if all focus cells share a box
  const box = BOX_OF[focus[0]!]!;
  if (focus.every(i => BOX_OF[i] === box)) return [...BOX_UNITS[box]!];

  // Mixed units (e.g. XY-Wing) — return the focus cells themselves
  return [...focus];
}

function buildExplanation(tech: TechResult, level: 1 | 2 | 3): string {
  const { technique, placement, eliminations, focusCells } = tech;

  if (level === 1) {
    switch (technique) {
      case 'naked-single':  return 'Look at this cell — it has only one possibility.';
      case 'hidden-single': return 'One digit can only go in one place in this unit.';
      case 'naked-pair':    return 'Two cells in this unit share the same two candidates.';
      case 'hidden-pair':   return 'Two digits in this unit are confined to two cells.';
      case 'pointing-pair': return 'A digit in this box is restricted to one row or column.';
      case 'box-line-reduction': return 'A digit in this line is restricted to one box.';
      case 'x-wing':        return 'A digit forms a rectangle across two rows and two columns.';
      case 'swordfish':     return 'A digit forms a pattern across three rows and columns.';
      case 'xy-wing':       return 'Three cells form a chain that eliminates a candidate.';
      default:              return 'Look for a pattern in this area.';
    }
  }

  if (level === 2) {
    const d = placement?.digit ?? eliminations[0]?.digit;
    const dStr = d != null ? ` for ${d}` : '';
    switch (technique) {
      case 'naked-single':
        return `This cell has only one candidate${dStr}.`;
      case 'hidden-single':
        return `Digit ${d} can only go in one cell in this unit.`;
      case 'naked-pair':
        return `These two cells share candidates — eliminate them from the rest of this unit.`;
      case 'hidden-pair':
        return `Digits ${d} and another are confined to these two cells${dStr}.`;
      case 'pointing-pair':
        return `Digit ${d} in this box is confined to one row/column, so eliminate it elsewhere.`;
      case 'box-line-reduction':
        return `Digit ${d} in this line stays inside one box, so eliminate it from the rest of the box.`;
      case 'x-wing':
        return `Digit ${d} forms an X-Wing — eliminate from the crossing lines.`;
      case 'swordfish':
        return `Digit ${d} forms a Swordfish — eliminate from the crossing lines.`;
      case 'xy-wing':
        return `This XY-Wing eliminates ${d} from cells seen by both pincers.`;
      default:
        return `Notice digit ${d} in these highlighted cells.`;
    }
  }

  // level 3: full explanation
  if (placement) {
    const { idx, digit } = placement;
    const r = ROW_OF[idx]! + 1, c = COL_OF[idx]! + 1;
    switch (technique) {
      case 'naked-single':
        return `Naked Single: cell (row ${r}, col ${c}) has only one candidate — place ${digit}.`;
      case 'hidden-single':
        return `Hidden Single: digit ${digit} can only go in row ${r}, column ${c} within its unit — place it.`;
      default:
        return `${technique}: place ${digit} at row ${r}, col ${c}.`;
    }
  }

  if (eliminations.length > 0) {
    const d = eliminations[0]!.digit;
    const count = eliminations.length;
    switch (technique) {
      case 'naked-pair':
        return `Naked Pair: eliminate ${d} (and its pair partner) from ${count} cell${count > 1 ? 's' : ''} in this unit.`;
      case 'hidden-pair':
        return `Hidden Pair: these two cells can only contain a pair of digits — remove all others from them.`;
      case 'pointing-pair':
        return `Pointing Pair/Triple: digit ${d} in this box lies entirely in one row/column — eliminate it from ${count} other cell${count > 1 ? 's' : ''} in that line.`;
      case 'box-line-reduction':
        return `Box/Line Reduction: digit ${d} in this line is confined to one box — eliminate it from ${count} other cell${count > 1 ? 's' : ''} in the box.`;
      case 'x-wing':
        return `X-Wing on ${d}: eliminate it from ${count} cell${count > 1 ? 's' : ''} in the crossing lines.`;
      case 'swordfish':
        return `Swordfish on ${d}: eliminate it from ${count} cell${count > 1 ? 's' : ''} in the crossing lines.`;
      case 'xy-wing':
        return `XY-Wing: eliminate ${d} from ${count} cell${count > 1 ? 's' : ''} seen by both pincers.`;
    }
  }

  return `${technique} applies here.`;
}

export function nextHint(b: Board, level: 1 | 2 | 3): Hint | null {
  if (isSolved(b)) return null;

  for (const fn of HUMAN_TECHNIQUES) {
    const tech = fn(b);
    if (!tech) continue;

    const cells: CellIdx[] =
      level === 1 ? regionFor(tech.focusCells[0]!, tech) :
      level === 2 ? [...tech.focusCells] :
      tech.placement ? [tech.placement.idx] : [...tech.focusCells];

    const digit: Digit | undefined =
      level === 1 ? undefined :
      (tech.placement?.digit ?? tech.eliminations[0]?.digit);

    const explanation = buildExplanation(tech, level);

    return {
      technique: tech.technique,
      cells: [...new Set(cells)].sort((a, b) => a - b),
      digit,
      explanation,
      level,
    };
  }

  // No human technique found: return a guess-based hint (solver picks a cell)
  return {
    technique: 'guess',
    cells: [],
    digit: undefined,
    explanation: level === 3
      ? 'No single logical step is available — try a candidate and see if it leads to a contradiction.'
      : 'This puzzle requires trial and error at this point.',
    level,
  };
}
