export type ThemeChoice = 'light' | 'dark' | 'system';
const KEY = 'bilko_sudoku_theme_v1';
const CB_KEY = 'bilko_sudoku_cb_v1';

export function getTheme(): ThemeChoice {
  const v = localStorage.getItem(KEY);
  return v === 'light' || v === 'dark' ? v : 'system';
}

export function setTheme(c: ThemeChoice) {
  if (c === 'system') {
    delete document.documentElement.dataset.theme;
    localStorage.removeItem(KEY);
  } else {
    document.documentElement.dataset.theme = c;
    localStorage.setItem(KEY, c);
  }
}

export function getColorBlind(): boolean {
  return localStorage.getItem(CB_KEY) === '1';
}

export function setColorBlind(on: boolean) {
  if (on) {
    document.documentElement.dataset.cb = '1';
    localStorage.setItem(CB_KEY, '1');
  } else {
    delete document.documentElement.dataset.cb;
    localStorage.removeItem(CB_KEY);
  }
}
