import { bus } from '../../lib/bus.js';
import { haptics } from './haptics.js';
import { sound } from './sound.js';

export { haptics, isHapticsEnabled, setHapticsEnabled } from './haptics.js';
export { sound, isSoundsEnabled, setSoundsEnabled } from './sound.js';

export function initFeedback(): void {
  bus.on('cellChanged', ({ value, isNote }) => {
    if (value == null) { haptics.tick(); sound.eraser(); return; }
    if (isNote) { haptics.tick(); sound.note(); }
    else { haptics.tap(); sound.place(); }
  });
  bus.on('mistakePlaced', () => {
    haptics.bump(); sound.error();
  });
  bus.on('puzzleSolved', () => {
    haptics.success(); sound.win();
  });
}
