import { useEffect, useState } from 'react';
import { useSaveState } from '../lib/platform.js';
import { useStore, STORAGE_KEY, type SerializedSave } from './store.js';

export function CloudSaveBridge() {
  const cloud = useSaveState<SerializedSave & { lastSaved?: number }>('sudoku');
  const [showResume, setShowResume] = useState(false);
  const board = useStore(s => s.board);

  useEffect(() => {
    if (cloud.loading || !cloud.blob) return;
    const localSave = (() => {
      try { return JSON.parse(localStorage.getItem(STORAGE_KEY) ?? 'null') as (SerializedSave & { lastSaved?: number }) | null; }
      catch { return null; }
    })();
    if (!localSave || cloud.updated_at > (localSave.lastSaved ?? 0)) {
      setShowResume(true);
      const t = setTimeout(() => setShowResume(false), 5000);
      return () => clearTimeout(t);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [cloud.loading, cloud.updated_at]);

  // Push to cloud whenever the board changes (debounced by the store's own persist timer)
  useEffect(() => {
    if (cloud.loading) return;
    const raw = (() => {
      try { return localStorage.getItem(STORAGE_KEY); } catch { return null; }
    })();
    if (!raw) return;
    void cloud.save({ ...JSON.parse(raw) as SerializedSave, lastSaved: Date.now() });
  // board as dep drives this; cloud.save is stable from the stub
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [board]);

  if (!showResume || !cloud.blob) return null;
  return (
    <div className="resume-modal" role="dialog" aria-label="Resume cloud save">
      <p>Found a more recent game on another device.</p>
      <button
        onClick={() => {
          useStore.getState().actions.loadFromCloud(cloud.blob!);
          setShowResume(false);
        }}
      >
        Resume cloud
      </button>
      <button onClick={() => setShowResume(false)}>Keep local</button>
    </div>
  );
}
