import { useState } from 'react';
import { bus } from '../../lib/bus.js';
import { GlossaryModal } from '../hints/GlossaryModal.js';

interface Props {
  canUndo: boolean;
  canRedo: boolean;
  noteMode: boolean;
  hintsUsed: number;
}

export function Toolbar({ canUndo, canRedo, noteMode, hintsUsed }: Props) {
  const [showGlossary, setShowGlossary] = useState(false);

  function erase() {
    // row:-2 is a sentinel; the state reducer uses current selection
    bus.emit('cellChanged', { row: -2, col: -2, value: null, isNote: false });
  }

  return (
    <>
      <div className="toolbar" role="toolbar" aria-label="Tools">
        <button className="tb-btn" onClick={erase} aria-label="Erase cell">⌫</button>
        <button
          className="tb-btn"
          disabled={!canUndo}
          onClick={() => bus.emit('undoRequested', {})}
          aria-label="Undo"
        >↶</button>
        <button
          className="tb-btn"
          disabled={!canRedo}
          onClick={() => bus.emit('redoRequested', {})}
          aria-label="Redo"
        >↷</button>
        <button
          className="tb-btn hint"
          onClick={() => bus.emit('hintRequested', { level: 1 })}
          aria-label={`Hint, ${hintsUsed} used`}
        >
          💡{hintsUsed > 0 ? <span className="badge">{hintsUsed}</span> : null}
        </button>
        <button
          className={`tb-btn${noteMode ? ' on' : ''}`}
          data-active={noteMode || undefined}
          onClick={() => bus.emit('modeChanged', { noteMode: !noteMode })}
          aria-pressed={noteMode}
          aria-label="Notes mode"
        >✏️</button>
        <button
          className="tb-btn"
          onClick={() => setShowGlossary(true)}
          aria-label="Open technique glossary"
        >?</button>
      </div>
      {showGlossary && (
        <GlossaryModal initial="naked-single" onClose={() => setShowGlossary(false)} />
      )}
    </>
  );
}
