import { useEffect, useReducer, useRef, useState } from 'react';
import { getTheme, setTheme, getColorBlind, setColorBlind, type ThemeChoice } from './theme.js';
import { isHapticsEnabled, setHapticsEnabled, isSoundsEnabled, setSoundsEnabled } from '../feedback/index.js';
import './theme.css';

export function ThemeMenu() {
  const [open, setOpen] = useState(false);
  const [t, setT] = useState<ThemeChoice>(getTheme);
  const [cb, setCb] = useState(getColorBlind);
  const [, forceUpdate] = useReducer((x: number) => x + 1, 0);
  const btnRef = useRef<HTMLButtonElement>(null);
  const popoverRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function offClick(e: MouseEvent) {
      if (
        popoverRef.current && !popoverRef.current.contains(e.target as Node) &&
        btnRef.current && !btnRef.current.contains(e.target as Node)
      ) setOpen(false);
    }
    function onEscape(e: KeyboardEvent) {
      if (e.key === 'Escape') { setOpen(false); btnRef.current?.focus(); }
    }
    if (open) {
      document.addEventListener('mousedown', offClick);
      document.addEventListener('keydown', onEscape);
    }
    return () => {
      document.removeEventListener('mousedown', offClick);
      document.removeEventListener('keydown', onEscape);
    };
  }, [open]);

  function pick(c: ThemeChoice) { setTheme(c); setT(c); }
  function toggleCb() { const next = !cb; setColorBlind(next); setCb(next); }

  return (
    <div className="theme-menu">
      <button
        ref={btnRef}
        onClick={() => setOpen(o => !o)}
        aria-label="Theme settings"
        aria-expanded={open}
        aria-haspopup="true"
        className="theme-btn"
      >
        Aa
      </button>
      {open && (
        <div ref={popoverRef} className="theme-popover">
          <fieldset>
            <legend>Theme</legend>
            {(['light', 'dark', 'system'] as ThemeChoice[]).map(c => (
              <label key={c}>
                <input
                  type="radio"
                  name="theme"
                  value={c}
                  checked={c === t}
                  onChange={() => pick(c)}
                />
                {c.charAt(0).toUpperCase() + c.slice(1)}
              </label>
            ))}
          </fieldset>
          <hr />
          <label>
            <input type="checkbox" checked={cb} onChange={toggleCb} />
            Color-blind safe
          </label>
          <label>
            <input
              type="checkbox"
              checked={isHapticsEnabled()}
              onChange={e => { setHapticsEnabled(e.target.checked); forceUpdate(); }}
            />
            Haptics
          </label>
          <label>
            <input
              type="checkbox"
              checked={isSoundsEnabled()}
              onChange={e => { setSoundsEnabled(e.target.checked); forceUpdate(); }}
            />
            Sounds
          </label>
        </div>
      )}
    </div>
  );
}
