const KEY = 'bilko_sudoku_haptics_v1';

function enabled(): boolean { return localStorage.getItem(KEY) !== '0'; }

function vib(pattern: number | number[]): void {
  if (!enabled()) return;
  if (typeof navigator?.vibrate === 'function') navigator.vibrate(pattern);
}

export const haptics = {
  tap:     () => vib(10),
  tick:    () => vib(5),
  bump:    () => vib([20, 60, 20]),
  success: () => vib([15, 60, 15, 60, 30]),
};

export function setHapticsEnabled(on: boolean): void {
  localStorage.setItem(KEY, on ? '1' : '0');
}
export function isHapticsEnabled(): boolean { return enabled(); }
