export function Notes({ digits }: { digits: number[] }) {
  return (
    <div className="sudoku-notes" aria-hidden="true">
      {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(d => (
        <span key={d} className={digits.includes(d) ? 'on' : 'off'}>
          {digits.includes(d) ? d : ''}
        </span>
      ))}
    </div>
  );
}
